#include <stdio.h>
#include <stdlib.h>

/* Device Driver Structure */
struct device_driver {
    char *name;
    int (*init)(void);      /* Initialization function */
    int (*read)(void *buf, int len);
    int (*write)(void *buf, int len);
    int (*ioctl)(int cmd, void *arg);
};

/* Example: Simple keyboard driver */
int keyboard_init(void) {
    printf("Keyboard driver initialized\n");
    return 0;
}

int keyboard_read(void *buffer, int length) {
    /* Read keyboard input */
    printf("Reading keyboard input...\n");
    return 0;
}

struct device_driver keyboard_driver = {
    .name = "PS/2 Keyboard",
    .init = keyboard_init,
    .read = keyboard_read,
    .write = NULL,  /* Keyboard is read-only */
    .ioctl = NULL
};

/* Main function demonstrating driver registration */
int main() {
    /* Register and initialize device drivers during OS boot */
    printf("OS Generation: Loading device drivers...\n");

    keyboard_driver.init();

    printf("All drivers loaded successfully\n");
    return 0;
}
